#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int cmp_int(const void *a, const void *b) {
    int x = *(const int *)a, y = *(const int *)b;
    return (x > y) - (x < y);
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int *A = (int*)malloc(N*sizeof(int));
        int *B = (int*)malloc(N*sizeof(int));
        for (int i=0;i<N;i++) scanf("%d", &A[i]), B[i]=A[i];
        qsort(B, N, sizeof(int), cmp_int);
        // collect operations
        int ops_cap = N/2;
        int *t = (int*)malloc(ops_cap*sizeof(int));
        int *p = (int*)malloc(ops_cap*sizeof(int));
        int *k = (int*)malloc(ops_cap*sizeof(int));
        int opcnt = 0;
        for (int i=N-1; i>=N-ops_cap && i>=0; --i) {
            unsigned int cur = (unsigned int)A[i];
            unsigned int want = (unsigned int)B[i];
            unsigned int diff = (want - cur) & ((1u<<30)-1);
            if (diff) {
                t[opcnt] = 2; // type 2: add K to suffix
                p[opcnt] = i+1; // 1‑based index
                k[opcnt] = diff;
                // apply to A for correctness of later steps
                for (int j=i; j<N; ++j) A[j] = (A[j] + diff) & ((1<<30)-1);
                ++opcnt;
            }
        }
        printf("%d\n", opcnt);
        for (int i=0;i<opcnt;i++) {
            printf("%d %d %u\n", t[i], p[i], k[i]);
        }
        free(A); free(B); free(t); free(p); free(k);
    }
    return 0;
}

