// COMPLETE, COMPILABLE Java 17 code
import java.io.*;
import java.util.*;
public class Main {
    static final int MOD = (1<<30)-1; // mask for 30 bits
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            int[] A = new int[N];
            int[] B = new int[N];
            for (int i = 0; i < N; i++) {
                A[i] = fs.nextInt();
                B[i] = A[i];
            }
            Arrays.sort(B);
            int limit = N/2;
            List<int[]> ops = new ArrayList<>();
            for (int i = N - 1; i >= N - limit && i >= 0; i--) {
                int cur = A[i];
                int want = B[i];
                int diff = (want - cur) & ((1 << 30) - 1);
                if (diff != 0) {
                    ops.add(new int[]{2, i + 1, diff});
                    for (int j = i; j < N; j++) {
                        A[j] = (A[j] + diff) & ((1 << 30) - 1);
                    }
                }
            }
            out.append(ops.size()).append('\n');
            for (int[] op : ops) {
                out.append(op[0]).append(' ').append(op[1]).append(' ').append(op[2]).append('\n');
            }
        }
        System.out.print(out.toString());
    }
    // fast scanner
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) { len = in.read(buffer); ptr = 0; if (len <= 0) return -1; }
            return buffer[ptr++];
        }
        int nextInt() throws IOException {
            int c, sign = 1, val = 0;
            do { c = readByte(); } while (c <= ' ');
            if (c == '-') { sign = -1; c = readByte(); }
            while (c > ' ') { val = val * 10 + (c - '0'); c = readByte(); }
            return val * sign;
        }
    }
}

