let out = [];
for (let tc = 0; tc < T; ++tc) {
  const N = input[idx++];
  let A = new Array(N);
  for (let i = 0; i < N; ++i) A[i] = input[idx++];
  const B = [...A].sort((x, y) => x - y);
  const limit = Math.floor(N / 2);
  const ops = [];
  for (let i = N - 1; i >= N - limit && i >= 0; --i) {
    const cur = A[i];
    const want = B[i];
    const diff = (want - cur) & ((1 << 30) - 1);
    if (diff !== 0) {
      ops.push([2, i + 1, diff]);
      for (let j = i; j < N; ++j) {
        A[j] = (A[j] + diff) & ((1 << 30) - 1);
      }
    }
  }
  out.push(String(ops.length));
  for (const [t, p, k] of ops) out.push(`${t} ${p} ${k}`);
